#!/usr/bin/env bash
#
# test-check-commit-signing.sh -- tests for scripts/check-commit-signing.sh and
# the pre-commit wiring that invokes it (#2625).
#
# Hermetic. Every case runs in a throwaway repository under a temp dir, signs with
# an EPHEMERAL ssh key generated by the test, and never touches the developer's
# 1Password signer, ssh-agent, or global git config. That matters twice over: the
# suite is deterministic in CI where no agent exists, and a test cannot pass by
# accidentally borrowing the developer's working signer.
#
# Run: bash scripts/test-check-commit-signing.sh
#
# Every case asserts its own preconditions before asserting its result. A signing
# test that passes because the setup silently failed to configure signing is worse
# than no test: it reports the guard works while proving nothing. Where a case
# claims "X is rejected", it first establishes that X was genuinely attempted.

set -euo pipefail

REPO_ROOT=$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)
CHECK="$REPO_ROOT/scripts/check-commit-signing.sh"
HOOK="$REPO_ROOT/.githooks/pre-commit"

WORK=$(mktemp -d)
trap 'rm -rf "$WORK"' EXIT

# Isolate every git invocation below -- the fixtures AND the check script under
# test -- from the developer's global and system config. Exported so the check
# script inherits it too, since it reads config from whatever repo it runs in.
#
# Not optional: without it, fixtures silently inherit real values. The "no signing
# key configured" case initially passed a key through from global config and its
# precondition caught it, which is the only reason this was noticed rather than
# quietly weakening several cases.
export GIT_CONFIG_GLOBAL=/dev/null
export GIT_CONFIG_SYSTEM=/dev/null

PASSED=0
FAILED=0

ok() {
    echo "  PASS  $1"
    PASSED=$((PASSED + 1))
}

bad() {
    echo "  FAIL  $1" >&2
    [ $# -gt 1 ] && printf '        %s\n' "${@:2}" >&2
    FAILED=$((FAILED + 1))
}

# A precondition that does not hold invalidates the case rather than failing it.
# Reported loudly and counted as a failure -- never skipped quietly.
require() {
    if ! eval "$1"; then
        bad "PRECONDITION FAILED: $1" "${@:2}"
        return 1
    fi
    return 0
}

# --------------------------------------------------------------------------
# Fixtures
# --------------------------------------------------------------------------

# An ephemeral ssh key, used for FILE-based signing: git invokes ssh-keygen with
# the private key on disk, so no agent and no 1Password are involved.
SIGNING_KEY="$WORK/id_test"
ssh-keygen -q -t ed25519 -N '' -C 'signing test key' -f "$SIGNING_KEY"

# new_repo <name> [extra git config args...]
# Creates a repo with an isolated config: core.hooksPath is emptied so the
# developer's installed hooks never fire inside a fixture.
new_repo() {
    local name="$1"
    shift
    local dir="$WORK/$name"
    mkdir -p "$dir" "$WORK/nohooks-$name"
    git init -q "$dir"
    git -C "$dir" config core.hooksPath "$WORK/nohooks-$name"
    git -C "$dir" config user.name "Test"
    git -C "$dir" config user.email "test@localhost"
    printf '%s\n' "$dir"
}

# Configures a repo to sign with the ephemeral key via plain ssh-keygen.
enable_working_signer() {
    local dir="$1"
    git -C "$dir" config commit.gpgsign true
    git -C "$dir" config gpg.format ssh
    git -C "$dir" config user.signingkey "$SIGNING_KEY"
    # Pin the signer to plain ssh-keygen. GIT_CONFIG_GLOBAL already blocks the
    # developer's op-ssh-sign from leaking in; this states the intent locally so
    # the fixture does not depend on that isolation being in place.
    git -C "$dir" config gpg.ssh.program ssh-keygen
}

# Runs the check inside a repo. Prints combined output; returns the exit code.
run_check() {
    local dir="$1"
    shift
    (cd "$dir" && env "$@" bash "$CHECK" 2>&1)
}

# --------------------------------------------------------------------------
# Control: prove the ephemeral key really signs.
# --------------------------------------------------------------------------
# Everything below distinguishes "signed" from "unsigned", so a key that cannot
# sign at all would make several cases pass for the wrong reason.
echo "Control: ephemeral signing key produces a real signature"
CTRL=$(new_repo control)
enable_working_signer "$CTRL"
git -C "$CTRL" commit -q --allow-empty -S -m "control"
if git -C "$CTRL" cat-file commit HEAD | sed -n '1,/^$/p' | grep -q '^gpgsig'; then
    ok "ephemeral key signs (gpgsig header present)"
else
    bad "ephemeral key does NOT sign -- every case below is invalid"
    exit 1
fi

# --------------------------------------------------------------------------
# Case 1: the misleading %G? signal
# --------------------------------------------------------------------------
# Would catch: any future rewrite of the check that reaches for the obvious
# `git log --format=%G?` instead of the raw commit object. Observed during the
# #2624 recovery: a correctly signed commit reported N.
echo
echo "Case 1: %G? reports N for a genuinely signed commit (allowedSignersFile unset)"
if require "[ -z \"\$(git -C '$CTRL' config --get gpg.ssh.allowedSignersFile || true)\" ]" \
    "the trap only occurs when allowedSignersFile is unset"; then
    G_STATUS=$(git -C "$CTRL" log -1 --format='%G?')
    HAS_SIG=$(git -C "$CTRL" cat-file commit HEAD | sed -n '1,/^$/p' | grep -c '^gpgsig' || true)
    if [ "$G_STATUS" = "N" ] && [ "$HAS_SIG" -eq 1 ]; then
        ok "%G? reports 'N' while the raw object carries gpgsig -- trap reproduced"
    else
        bad "trap not reproduced: %G?='$G_STATUS', gpgsig count=$HAS_SIG" \
            "If %G? no longer reports N here, git's behavior changed;" \
            "re-verify that the check still avoids %G? for the right reason."
    fi

    # And the check itself must pass on this commit. A %G?-based implementation
    # would fail it -- which is the whole point.
    if OUT=$(run_check "$CTRL" SW_REQUIRE_SIGNED_COMMITS=1); then
        ok "check passes on a signed repo despite %G? reporting N"
    else
        bad "check rejected a correctly signed repo (regressed onto %G?)" "$OUT"
    fi
fi

# --------------------------------------------------------------------------
# Case 2: signed commit allowed
# --------------------------------------------------------------------------
# Would catch: a check that fails closed on everything, which would "block
# unsigned commits" trivially by blocking all commits.
echo
echo "Case 2: signing required and working -> allowed"
R2=$(new_repo signed-ok)
enable_working_signer "$R2"
if require "[ \"\$(git -C '$R2' config --get commit.gpgsign)\" = true ]"; then
    if OUT=$(run_check "$R2" SW_REQUIRE_SIGNED_COMMITS=1); then
        if grep -q 'PASS signed-commits' <<< "$OUT"; then
            ok "exit 0 and reports PASS"
        else
            bad "exit 0 but did not report PASS" "$OUT"
        fi
    else
        bad "rejected a correctly configured repo" "$OUT"
    fi
fi

# --------------------------------------------------------------------------
# Case 3: unsigned commit blocked
# --------------------------------------------------------------------------
# The #2624 case. Would catch: a check that infers the requirement from
# commit.gpgsign, which would conclude "signing not required" here and pass --
# vacuous in precisely the situation it exists for.
echo
echo "Case 3: signing required but commit.gpgsign off -> blocked"
R3=$(new_repo unsigned-blocked)
enable_working_signer "$R3"
git -C "$R3" config commit.gpgsign false
# Precondition: prove this repo genuinely produces an UNSIGNED commit. Without
# this, the case could pass against a config that was never actually unsigned.
git -C "$R3" commit -q --allow-empty -m "would-be-unsigned"
UNSIGNED_COUNT=$(git -C "$R3" cat-file commit HEAD | sed -n '1,/^$/p' | grep -c '^gpgsig' || true)
if require "[ '$UNSIGNED_COUNT' -eq 0 ]" \
    "this repo must actually produce unsigned commits for the case to mean anything"; then
    if OUT=$(run_check "$R3" SW_REQUIRE_SIGNED_COMMITS=1); then
        bad "ALLOWED a repo that demonstrably creates unsigned commits" "$OUT"
    else
        if grep -q 'commit.gpgsign' <<< "$OUT" && grep -q 'SSH_AUTH_SOCK' <<< "$OUT"; then
            ok "blocked, naming both the cause (commit.gpgsign) and the SSH_AUTH_SOCK remedy"
        else
            bad "blocked but the message omits the cause or the remedy" "$OUT"
        fi
    fi
fi

# --------------------------------------------------------------------------
# Case 4: signing requirement absent -> no-op
# --------------------------------------------------------------------------
# Would catch: a check that ignores the requirement flag. The signer here is
# deliberately BROKEN, so any probe would fail -- passing proves the check
# short-circuited rather than merely got lucky.
echo
echo "Case 4: signing not required -> no-op (and no probe runs)"
R4=$(new_repo not-required)
git -C "$R4" config commit.gpgsign false
git -C "$R4" config gpg.format ssh
git -C "$R4" config gpg.ssh.program /nonexistent/signer
if require "[ ! -f '$R4/.githooks/signed-commits-required' ]" \
    "no marker file must be present"; then
    if OUT=$(run_check "$R4" SW_REQUIRE_SIGNED_COMMITS=0); then
        if grep -q 'SKIP signed-commits' <<< "$OUT"; then
            ok "exit 0 with SKIP, despite a broken signer (probe was skipped)"
        else
            bad "exit 0 but did not report SKIP" "$OUT"
        fi
    else
        bad "failed a repo that does not require signing" "$OUT"
    fi
fi

# --------------------------------------------------------------------------
# Case 5: requirement comes from the tracked marker file
# --------------------------------------------------------------------------
# Would catch: a marker file that is never read, leaving enforcement dependent on
# an env var nobody sets -- i.e. off by default in real use.
echo
echo "Case 5: marker file alone (no env var) enables enforcement"
R5=$(new_repo marker-driven)
git -C "$R5" config commit.gpgsign false
if require "[ -z \"\${SW_REQUIRE_SIGNED_COMMITS:-}\" ]" "env override must be unset"; then
    # Without the marker: no-op.
    if OUT=$(run_check "$R5"); then
        if grep -q 'SKIP' <<< "$OUT"; then
            ok "no marker -> SKIP"
        else
            bad "no marker but no SKIP" "$OUT"
        fi
    else
        bad "no marker but the check failed" "$OUT"
    fi
    # With the marker: enforced.
    mkdir -p "$R5/.githooks"
    touch "$R5/.githooks/signed-commits-required"
    if OUT=$(run_check "$R5"); then
        bad "marker present but the unsigned repo was allowed" "$OUT"
    else
        ok "marker present -> enforced"
    fi
fi

# --------------------------------------------------------------------------
# Case 6: unreachable / failing signer
# --------------------------------------------------------------------------
# Criterion: an unreachable signer is a clear actionable error, never a silent
# fallback to an unsigned commit. Would catch: a probe whose failure is swallowed.
echo
echo "Case 6: signer unreachable -> actionable error, not a silent pass"
R6=$(new_repo broken-signer)
enable_working_signer "$R6"
git -C "$R6" config gpg.ssh.program /nonexistent/op-ssh-sign
# Precondition: prove git genuinely cannot commit with this config, so the case
# is testing signer failure rather than an unrelated misconfiguration.
if git -C "$R6" commit -q --allow-empty -S -m "should not exist" 2>/dev/null; then
    bad "PRECONDITION FAILED: the 'broken' signer produced a commit"
elif require "[ \"\$(git -C '$R6' rev-list --count --all)\" -eq 0 ]" \
    "no commit should exist after the failed signing attempt"; then
    if OUT=$(run_check "$R6" SW_REQUIRE_SIGNED_COMMITS=1); then
        bad "PASSED with an unreachable signer -- this is the silent-fallback bug" "$OUT"
    else
        if grep -q 'unreachable or failed' <<< "$OUT" &&
            grep -q '/nonexistent/op-ssh-sign' <<< "$OUT" &&
            grep -q 'SSH_AUTH_SOCK' <<< "$OUT"; then
            ok "blocked, surfacing git's own error, the signer path, and the remedy"
        else
            bad "blocked but the message is not actionable" "$OUT"
        fi
    fi
fi

# --------------------------------------------------------------------------
# Case 7: missing signing key
# --------------------------------------------------------------------------
echo
echo "Case 7: commit.gpgsign true but no signing key -> blocked"
R7=$(new_repo no-key)
git -C "$R7" config commit.gpgsign true
git -C "$R7" config gpg.format ssh
if require "[ -z \"\$(git -C '$R7' config --get user.signingkey || true)\" ]"; then
    if OUT=$(run_check "$R7" SW_REQUIRE_SIGNED_COMMITS=1); then
        bad "allowed a repo with no signing key" "$OUT"
    else
        if grep -q 'user.signingkey' <<< "$OUT"; then
            ok "blocked, naming user.signingkey"
        else
            bad "blocked but did not name user.signingkey" "$OUT"
        fi
    fi
fi

# --------------------------------------------------------------------------
# Case 8: the real pre-commit hook fires
# --------------------------------------------------------------------------
# The dominant failure mode for this whole change is a check that is correct and
# never runs. Cases 1-7 exercise the script; this one exercises the actual hook
# file, through a real `git commit`, and asserts NO COMMIT WAS CREATED.
#
# The signing check is section 0a, ahead of every expensive check, and section 0
# (conflict markers) passes trivially with nothing staged -- so the hook fails at
# 0a without ever reaching go build. That ordering is what makes this test cheap,
# and this test is what keeps that ordering honest.
echo
echo "Case 8: the real .githooks/pre-commit blocks a real git commit"
R8=$(new_repo hook-e2e)
# The hook resolves the check script via `git rev-parse --show-toplevel`, so the
# fixture needs the repo layout it expects.
mkdir -p "$R8/.githooks" "$R8/scripts"
cp "$HOOK" "$R8/.githooks/pre-commit"
cp "$CHECK" "$R8/scripts/check-commit-signing.sh"
chmod +x "$R8/.githooks/pre-commit" "$R8/scripts/check-commit-signing.sh"
touch "$R8/.githooks/signed-commits-required"
git -C "$R8" config core.hooksPath "$R8/.githooks"
enable_working_signer "$R8"
git -C "$R8" config commit.gpgsign false # the #2624 condition
echo "content" > "$R8/file.txt"
git -C "$R8" add file.txt
if require "[ -x '$R8/.githooks/pre-commit' ]" "hook must be installed and executable" &&
    require "[ \"\$(git -C '$R8' config --get core.hooksPath)\" = '$R8/.githooks' ]"; then
    set +e
    HOOK_OUT=$(git -C "$R8" commit -m "unsigned commit attempt" 2>&1)
    HOOK_STATUS=$?
    set -e
    COMMITS_AFTER=$(git -C "$R8" rev-list --count --all 2>/dev/null || echo 0)
    if [ "$HOOK_STATUS" -eq 0 ]; then
        bad "git commit SUCCEEDED -- the hook did not fire" "$HOOK_OUT"
    elif [ "$COMMITS_AFTER" -ne 0 ]; then
        bad "hook exited non-zero but a commit was still created" "$HOOK_OUT"
    elif grep -q 'signed-commits' <<< "$HOOK_OUT"; then
        ok "commit refused by the signing check, no commit object created"
    else
        bad "commit refused, but not by the signing check" "$HOOK_OUT"
    fi
fi

# --------------------------------------------------------------------------
# Case 9: the probe does not contaminate the real repository
# --------------------------------------------------------------------------
# Regression test for a real defect in this check's first draft.
#
# git exports GIT_INDEX_FILE into its hooks, and that variable outranks
# directory-based repo discovery. The probe -- `git -C <throwaway> commit
# --allow-empty` -- therefore picked up the CALLING repository's index and
# committed the developer's entire staged changeset onto the real branch, under
# the message "signing probe". It looked like the hook passing.
#
# Cases 1-8 all missed it: the script-level cases never run inside a hook, so
# GIT_INDEX_FILE is not set for them, and Case 8 fails before reaching the probe.
# The gap was specifically "the probe runs, from inside a real hook, and the
# commit succeeds" -- the success path, end to end. That is this case.
#
# THE FIXTURE MUST BE A WORKTREE. In an ordinary repository git exports
# GIT_INDEX_FILE as the relative path ".git/index", which `git -C <probe-repo>`
# harmlessly re-resolves against the probe repo. In a LINKED WORKTREE git exports
# it as an ABSOLUTE path into the main repo's .git/worktrees/<name>/index, which
# -C cannot override -- so only the worktree case contaminates. A first attempt at
# this test used a plain repo, and the reintroduced bug passed it cleanly.
#
# This project does all of its issue work in worktrees (see docs/worktrees.md), so
# the contaminating configuration is the normal one here, not the exotic one.
echo
echo "Case 9: probe leaves the real repo alone (worktree, hook runs, commit succeeds)"
# Main repo plus a linked worktree -- the shape that reproduces the defect.
R9_MAIN="$WORK/probe-isolation-main"
R9="$WORK/probe-isolation-wt"
git init -q "$R9_MAIN"
git -C "$R9_MAIN" config user.name "Test"
git -C "$R9_MAIN" config user.email "test@localhost"
git -C "$R9_MAIN" commit -q --allow-empty --no-verify -m "root"
git -C "$R9_MAIN" worktree add -q "$R9" -b probe-isolation
if ! require "[ -f '$R9/.git' ]" "fixture must be a LINKED worktree (.git is a file, not a dir)"; then
    bad "Case 9 fixture is not a worktree -- it cannot reproduce the defect"
fi
mkdir -p "$R9/.githooks" "$R9/scripts"
cp "$HOOK" "$R9/.githooks/pre-commit"
cp "$CHECK" "$R9/scripts/check-commit-signing.sh"
chmod +x "$R9/.githooks/pre-commit" "$R9/scripts/check-commit-signing.sh"
touch "$R9/.githooks/signed-commits-required"
# Unlike Case 8, this case runs the hook all the way THROUGH, so the fixture needs
# what the hook's later sections read unconditionally. Everything else in the hook
# skips on its own (nothing staged matches it).
cp "$REPO_ROOT/.markdownlint-cli2-version" "$R9/.markdownlint-cli2-version"
git -C "$R9" config core.hooksPath "$R9/.githooks"
enable_working_signer "$R9"
echo "real content" > "$R9/real.txt"
git -C "$R9" add real.txt
BEFORE=$(git -C "$R9" rev-list --count HEAD)
if require "[ '$BEFORE' -eq 1 ]" "exactly one baseline commit expected"; then
    set +e
    C9_OUT=$(git -C "$R9" commit -m "real developer commit" 2>&1)
    C9_STATUS=$?
    set -e
    AFTER=$(git -C "$R9" rev-list --count HEAD)
    SUBJECTS=$(git -C "$R9" log --format='%s' | tr '\n' '|')
    if [ "$C9_STATUS" -ne 0 ]; then
        bad "the commit was refused on the success path" "$C9_OUT"
    elif [ "$AFTER" -ne 2 ]; then
        bad "expected 2 commits, found $AFTER -- the probe leaked into the real repo" \
            "subjects: $SUBJECTS"
    elif grep -q 'signing probe' <<< "$SUBJECTS"; then
        bad "a 'signing probe' commit landed in the real repository" "subjects: $SUBJECTS"
    elif ! git -C "$R9" cat-file commit HEAD | sed -n '1,/^$/p' | grep -q '^gpgsig'; then
        bad "the developer's commit was created but is not signed"
    else
        # And the staged file must actually be in the commit -- if the probe had
        # consumed the index, the real commit would be empty.
        if git -C "$R9" show --name-only --format= HEAD | grep -q '^real.txt$'; then
            ok "exactly one signed commit, the developer's, with the staged file intact"
        else
            bad "commit created but real.txt is missing -- the index was consumed" \
                "$(git -C "$R9" show --name-only --format= HEAD)"
        fi
    fi
fi

# --------------------------------------------------------------------------
echo
echo "----------------------------------------"
echo "passed: $PASSED  failed: $FAILED"
if [ "$FAILED" -ne 0 ]; then
    exit 1
fi
echo "All signed-commit checks behaved as specified."
